import { useCart } from '../hooks/useCart';

interface Product {
  id: string;
  name: string;
  price: number;
  image: string;
}

const ProductCard = ({ product }: { product: Product }) => {
  const { addToCart } = useCart();

  return (
    <div className="bg-gray-800/60 border border-gray-700/50 rounded-2xl p-6 hover:border-indigo-500/50 hover:bg-gray-800 transition-all duration-200">
      <img src={product.image} alt={product.name} className="w-full h-48 object-cover rounded-xl mb-4" />
      <h3 className="text-white font-medium mb-1">{product.name}</h3>
      <p className="text-gray-400 text-sm mb-4">${product.price.toFixed(2)}</p>
      <button
        onClick={() => addToCart(product)}
        className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition"
      >
        Add to Cart
      </button>
    </div>
  );
};

export default ProductCard;

